CREATE OR REPLACE FUNCTION public.crear_bloqueo(payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id_cabana            BIGINT;
  v_fecha_desde          DATE;
  v_fecha_hasta          DATE;
  v_motivo               TEXT;
  v_descripcion          TEXT;
  v_creado_por           TEXT;
  v_source_event         TEXT;
  v_id_bloqueo           BIGINT;
  v_reservas_ids         BIGINT[];
  v_prereservas_ids      BIGINT[];
  v_bloqueos_ids         BIGINT[];
BEGIN
  -- 1. Extraer payload (v1.7.2 — extract defensivo unificado)
  -- Todos los campos derivados de payload->>'...' pasan por
  -- NULLIF(TRIM(...),'') antes del cast. Esto:
  --   - normaliza "" y whitespace puro ("   ") a NULL real
  --   - evita errores crudos de cast en BIGINT y DATE
  --   - mantiene el contrato: las validaciones siguen rebotando con
  --     payload_invalido cuando un obligatorio queda NULL.
  --
  -- Caso especial v_id_cabana: null significa "bloqueo total" (válido).
  -- Tanto null como "" como "   " se interpretan como bloqueo total.
  v_id_cabana    := NULLIF(TRIM(payload->>'id_cabana'), '')::BIGINT;
  v_fecha_desde  := NULLIF(TRIM(payload->>'fecha_desde'), '')::DATE;
  v_fecha_hasta  := NULLIF(TRIM(payload->>'fecha_hasta'), '')::DATE;
  v_motivo       := NULLIF(TRIM(payload->>'motivo'), '');
  v_descripcion  := NULLIF(TRIM(payload->>'descripcion'), '');
  v_creado_por   := NULLIF(TRIM(payload->>'creado_por'), '');
  v_source_event := NULLIF(TRIM(payload->>'source_event'), '');

  IF v_fecha_desde IS NULL OR v_fecha_hasta IS NULL
     OR v_motivo IS NULL OR v_creado_por IS NULL OR v_source_event IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'payload_invalido');
  END IF;

  IF v_fecha_hasta <= v_fecha_desde THEN
    RETURN jsonb_build_object('ok', false, 'error', 'fechas_invalidas');
  END IF;

  -- Guard temporal (Bloque 2 / motor de horarios): rechazar solo rangos
  -- completamente pasados en zona Argentina. fecha_hasta es exclusiva '[)':
  -- fecha_hasta <= hoy_ar => ultima noche cubierta <= ayer => rango vencido.
  -- Un bloqueo que empezo ayer pero sigue vigente (fecha_hasta > hoy_ar) pasa.
  IF v_fecha_hasta <= fecha_hoy_ar() THEN
    RETURN jsonb_build_object(
      'ok', false, 'error', 'rango_pasado',
      'campo', 'fecha_hasta', 'minimo', fecha_hoy_ar(), 'recibido', v_fecha_hasta
    );
  END IF;

  IF v_motivo NOT IN ('mantenimiento', 'uso_propio', 'tormenta', 'overbooking', 'otro') THEN
    RETURN jsonb_build_object('ok', false, 'error', 'motivo_invalido');
  END IF;

  -- 2. Locks (INVARIANTE DE LOCKS v1.5: SIEMPRE primero el global)
  PERFORM pg_advisory_xact_lock(10, 0);

  IF v_id_cabana IS NOT NULL THEN
    -- Bloqueo específico: tomar también lock por cabaña con cast a INTEGER (v1.6)
    PERFORM pg_advisory_xact_lock(1, v_id_cabana::INTEGER);

    -- Verificar cabaña existe
    IF NOT EXISTS (SELECT 1 FROM cabanas WHERE id_cabana = v_id_cabana) THEN
      RETURN jsonb_build_object('ok', false, 'error', 'cabana_no_existe');
    END IF;

    -- 3.A.1 Verificar conflicto con reservas confirmadas/activas en esta cabaña
    SELECT COALESCE(array_agg(id_reserva), ARRAY[]::BIGINT[])
    INTO v_reservas_ids
    FROM reservas
    WHERE id_cabana = v_id_cabana
      AND estado IN ('confirmada', 'activa')
      AND daterange(fecha_checkin, fecha_checkout, '[)')
          && daterange(v_fecha_desde, v_fecha_hasta, '[)');

    IF cardinality(v_reservas_ids) > 0 THEN
      RETURN jsonb_build_object(
        'ok',                    false,
        'error',                 'conflicto_con_reserva',
        'reservas_en_conflicto', to_jsonb(v_reservas_ids)
      );
    END IF;

    -- 3.A.2 Verificar conflicto con pre-reservas vigentes en esta cabaña
    SELECT COALESCE(array_agg(id_pre_reserva), ARRAY[]::BIGINT[])
    INTO v_prereservas_ids
    FROM pre_reservas
    WHERE id_cabana = v_id_cabana
      AND (
        (estado = 'pendiente_pago' AND expira_en > NOW())
        OR estado = 'pago_en_revision'
      )
      AND daterange(fecha_in, fecha_out, '[)')
          && daterange(v_fecha_desde, v_fecha_hasta, '[)');

    IF cardinality(v_prereservas_ids) > 0 THEN
      RETURN jsonb_build_object(
        'ok',                       false,
        'error',                    'conflicto_con_prereserva',
        'prereservas_en_conflicto', to_jsonb(v_prereservas_ids),
        'motivo',                   'Hay pre-reservas vigentes en el rango. Cancelarlas antes de bloquear.'
      );
    END IF;

    -- 3.A.3 Verificar bloqueos solapados (específico vs específico o específico vs total)
    SELECT COALESCE(array_agg(id_bloqueo), ARRAY[]::BIGINT[])
    INTO v_bloqueos_ids
    FROM bloqueos
    WHERE activo = TRUE
      AND (id_cabana = v_id_cabana OR id_cabana IS NULL)
      AND daterange(fecha_desde, fecha_hasta, '[)')
          && daterange(v_fecha_desde, v_fecha_hasta, '[)');

    IF cardinality(v_bloqueos_ids) > 0 THEN
      RETURN jsonb_build_object(
        'ok',                    false,
        'error',                 'bloqueo_solapado',
        'bloqueos_en_conflicto', to_jsonb(v_bloqueos_ids),
        'motivo',                'Ya hay un bloqueo activo (específico o total) en el rango'
      );
    END IF;

  ELSE
    -- Bloqueo total (id_cabana IS NULL)
    -- 3.B.1 Verificar conflicto con reservas en cualquier cabaña
    SELECT COALESCE(array_agg(id_reserva), ARRAY[]::BIGINT[])
    INTO v_reservas_ids
    FROM reservas
    WHERE estado IN ('confirmada', 'activa')
      AND daterange(fecha_checkin, fecha_checkout, '[)')
          && daterange(v_fecha_desde, v_fecha_hasta, '[)');

    IF cardinality(v_reservas_ids) > 0 THEN
      RETURN jsonb_build_object(
        'ok',                    false,
        'error',                 'conflicto_con_reserva',
        'motivo',                'Hay reservas confirmadas en el rango. Resolver antes de bloquear el complejo.',
        'reservas_en_conflicto', to_jsonb(v_reservas_ids)
      );
    END IF;

    -- 3.B.2 Verificar conflicto con pre-reservas vigentes en cualquier cabaña
    SELECT COALESCE(array_agg(id_pre_reserva), ARRAY[]::BIGINT[])
    INTO v_prereservas_ids
    FROM pre_reservas
    WHERE (
        (estado = 'pendiente_pago' AND expira_en > NOW())
        OR estado = 'pago_en_revision'
      )
      AND daterange(fecha_in, fecha_out, '[)')
          && daterange(v_fecha_desde, v_fecha_hasta, '[)');

    IF cardinality(v_prereservas_ids) > 0 THEN
      RETURN jsonb_build_object(
        'ok',                       false,
        'error',                    'conflicto_con_prereserva',
        'prereservas_en_conflicto', to_jsonb(v_prereservas_ids),
        'motivo',                   'Hay pre-reservas vigentes en el rango. Cancelarlas antes de bloquear el complejo.'
      );
    END IF;

    -- 3.B.3 Verificar bloqueos solapados (total vs total o total vs específico existente)
    SELECT COALESCE(array_agg(id_bloqueo), ARRAY[]::BIGINT[])
    INTO v_bloqueos_ids
    FROM bloqueos
    WHERE activo = TRUE
      AND daterange(fecha_desde, fecha_hasta, '[)')
          && daterange(v_fecha_desde, v_fecha_hasta, '[)');

    IF cardinality(v_bloqueos_ids) > 0 THEN
      RETURN jsonb_build_object(
        'ok',                    false,
        'error',                 'bloqueo_solapado',
        'bloqueos_en_conflicto', to_jsonb(v_bloqueos_ids),
        'motivo',                'Ya hay bloqueos activos en el rango (totales o específicos)'
      );
    END IF;
  END IF;

  -- 4. INSERT con captura defensiva de exclusion_violation
  BEGIN
    INSERT INTO bloqueos (
      id_cabana, fecha_desde, fecha_hasta, motivo, descripcion,
      creado_por, activo, source_event
    ) VALUES (
      v_id_cabana, v_fecha_desde, v_fecha_hasta, v_motivo, v_descripcion,
      v_creado_por, TRUE, v_source_event
    )
    RETURNING id_bloqueo INTO v_id_bloqueo;

  EXCEPTION
    WHEN exclusion_violation THEN
      RETURN jsonb_build_object('ok', false, 'error', 'bloqueo_solapado',
                                'motivo', 'EXCLUDE detectó conflicto residual');
  END;

  -- 5. Log
  INSERT INTO log_cambios (
    tabla_afectada, id_registro, modificado_por, source_event, nivel, detalle
  ) VALUES (
    'bloqueos', v_id_bloqueo::TEXT, v_creado_por, v_source_event, 'info',
    jsonb_build_object(
      'evento',       'bloqueo_creado',
      'id_bloqueo',   v_id_bloqueo,
      'id_cabana',    v_id_cabana,
      'fecha_desde',  v_fecha_desde,
      'fecha_hasta',  v_fecha_hasta,
      'motivo',       v_motivo,
      'tipo_bloqueo', CASE WHEN v_id_cabana IS NULL THEN 'total' ELSE 'cabana_especifica' END
    )
  );

  RETURN jsonb_build_object(
    'ok',           true,
    'id_bloqueo',   v_id_bloqueo,
    'id_cabana',    v_id_cabana,
    'tipo_bloqueo', CASE WHEN v_id_cabana IS NULL THEN 'total' ELSE 'cabana_especifica' END
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.crear_override_horario(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fecha_desde date;
  v_fecha_hasta date   := NULL;
  v_id_cabana   bigint := NULL;
  v_tipo        text;
  v_valor       text;
  v_motivo      text;
  v_creado_por  text;
  v_activo      boolean := true;
  v_source      text   := NULL;
  v_id_override bigint;
  v_verd        jsonb;
  v_detalle_txt text;
  v_alcance     text;
  rec           record;
BEGIN
  -- Capa 0: lock global de disponibilidad SIEMPRE primero (antes de validar o insertar).
  PERFORM pg_advisory_xact_lock(10, 0);

  -- (1) estructura del payload
  IF p_payload IS NULL OR jsonb_typeof(p_payload) <> 'object' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'payload_invalido', 'detalle', 'payload no es objeto jsonb');
  END IF;

  -- (2) columnas que NO son parametros (las asigna la DB)
  IF (p_payload ? 'created_at') OR (p_payload ? 'id_override') THEN
    RETURN jsonb_build_object('ok', false, 'error', 'payload_invalido',
      'detalle', 'created_at/id_override no son parametros del payload; los asigna la DB');
  END IF;

  -- (3) requeridos presentes y no nulos
  IF (p_payload->>'fecha_desde')  IS NULL
     OR (p_payload->>'tipo_override') IS NULL
     OR (p_payload->>'valor')      IS NULL
     OR (p_payload->>'motivo')     IS NULL
     OR (p_payload->>'creado_por') IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'payload_invalido',
      'detalle', 'faltan requeridos: fecha_desde, tipo_override, valor, motivo, creado_por');
  END IF;

  -- (4) casts tipados; errores de cast (fecha/bigint/boolean) => payload_invalido
  BEGIN
    v_fecha_desde := (p_payload->>'fecha_desde')::date;
    IF (p_payload ? 'fecha_hasta') AND (p_payload->>'fecha_hasta') IS NOT NULL THEN
      v_fecha_hasta := (p_payload->>'fecha_hasta')::date;
    END IF;
    IF (p_payload ? 'id_cabana') AND (p_payload->>'id_cabana') IS NOT NULL THEN
      v_id_cabana := (p_payload->>'id_cabana')::bigint;
    END IF;
    IF (p_payload ? 'activo') AND (p_payload->>'activo') IS NOT NULL THEN
      v_activo := (p_payload->>'activo')::boolean;
    END IF;
  EXCEPTION
    WHEN invalid_text_representation OR datetime_field_overflow OR invalid_datetime_format THEN
      RETURN jsonb_build_object('ok', false, 'error', 'payload_invalido', 'detalle', 'cast de campo fallido (fecha/id_cabana/activo)');
  END;

  v_tipo       := p_payload->>'tipo_override';
  v_valor      := p_payload->>'valor';
  v_motivo     := p_payload->>'motivo';
  v_creado_por := p_payload->>'creado_por';
  IF (p_payload ? 'source_event') AND (p_payload->>'source_event') IS NOT NULL THEN
    v_source := p_payload->>'source_event';
  END IF;

  -- (5) coherencia de fechas (ademas del CHECK de tabla, para error limpio)
  IF v_fecha_hasta IS NOT NULL AND v_fecha_hasta < v_fecha_desde THEN
    RETURN jsonb_build_object('ok', false, 'error', 'payload_invalido', 'detalle', 'fecha_hasta < fecha_desde');
  END IF;

  -- (6) tipo soportado (S2: solo horarios)
  IF v_tipo NOT IN ('hora_checkin', 'hora_checkout') THEN
    RETURN jsonb_build_object('ok', false, 'error', 'tipo_override_no_soportado',
      'tipo_override', v_tipo, 'detalle', 'S2 solo admite hora_checkin/hora_checkout');
  END IF;

  -- (7) cabana existe (si es especifica); NULL = global estricto
  v_alcance := CASE WHEN v_id_cabana IS NULL THEN 'global_estricto' ELSE 'cabana' END;
  IF v_id_cabana IS NOT NULL AND NOT EXISTS (SELECT 1 FROM cabanas WHERE id_cabana = v_id_cabana) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'cabana_no_encontrada', 'id_cabana', v_id_cabana);
  END IF;

  -- (8) INSERT tentativo + validacion S0 en subtransaccion.
  BEGIN
    INSERT INTO overrides_operativos
      (fecha_desde, fecha_hasta, id_cabana, tipo_override, valor, motivo, creado_por, activo, source_event)
    VALUES
      (v_fecha_desde, v_fecha_hasta, v_id_cabana, v_tipo, v_valor, v_motivo, v_creado_por, v_activo, v_source)
    RETURNING id_override INTO v_id_override;

    -- Solo validar si queda ACTIVO (inactivo no afecta horarios; el trigger S1 tambien lo saltea).
    IF v_activo THEN
      FOR rec IN
        -- applied_set: (esa cabaña, o todas las activas si global) x [fecha_desde, COALESCE(fecha_hasta, fecha_desde)]  (R0)
        SELECT c.id_cabana AS id_cabana, g::date AS fecha
        FROM cabanas c
        CROSS JOIN LATERAL generate_series(v_fecha_desde, COALESCE(v_fecha_hasta, v_fecha_desde), interval '1 day') AS g
        WHERE (v_id_cabana IS NULL AND c.activa) OR (c.id_cabana = v_id_cabana)
      LOOP
        v_verd := validar_estado_override(rec.id_cabana, rec.fecha);
        IF NOT (v_verd->>'ok')::boolean THEN
          -- Falla esperada: llevar el verdict en DETAIL y forzar rollback de la subtransaccion.
          RAISE EXCEPTION 'validacion_override_fallida'
            USING ERRCODE = '45000', DETAIL = v_verd::text;
        END IF;
      END LOOP;
    END IF;
    -- Aca: valido (o inactivo). El insert tentativo persiste.
  EXCEPTION
    WHEN SQLSTATE '45000' THEN
      -- El insert tentativo se revirtio con la subtransaccion. Recuperar el verdict del DETAIL.
      GET STACKED DIAGNOSTICS v_detalle_txt = PG_EXCEPTION_DETAIL;
      v_verd := v_detalle_txt::jsonb;
      RETURN jsonb_build_object(
        'ok', false,
        'error', v_verd->>'error',
        'id_cabana', v_id_cabana,
        'alcance', v_alcance,
        'tipo_override', v_tipo,
        'fecha_desde', v_fecha_desde,
        'fecha_hasta', v_fecha_hasta,
        'detalle_validador', v_verd
      );
  END;

  RETURN jsonb_build_object(
    'ok', true,
    'id_override', v_id_override,
    'id_cabana', v_id_cabana,
    'alcance', v_alcance,
    'tipo_override', v_tipo,
    'valor', v_valor,
    'fecha_desde', v_fecha_desde,
    'fecha_hasta', v_fecha_hasta,
    'activo', v_activo,
    'nota', CASE WHEN NOT v_activo
                 THEN 'insertado inactivo: no afecta horarios ni dispara validacion (se revalida al activarse)'
                 ELSE NULL END
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_guard_overrides()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_applies boolean := false;
  v_new_applies boolean := false;
  v_old_id      text := NULL;
  v_new_id      text := NULL;
  rec           record;
  v_verd        jsonb;
BEGIN
  -- Capa 0: lock global de disponibilidad SIEMPRE primero (invariante, como crear_bloqueo).
  PERFORM pg_advisory_xact_lock(10, 0);

  -- Deteccion de cambio efectivo + lado activo por operacion (accesos OLD/NEW seguros por rama).
  IF TG_OP = 'INSERT' THEN
    v_new_applies := NEW.activo;
    IF NOT v_new_applies THEN RETURN NULL; END IF;             -- insert inactivo: sin efecto horario
    v_new_id := NEW.id_override::text;
  ELSIF TG_OP = 'DELETE' THEN
    v_old_applies := OLD.activo;
    IF NOT v_old_applies THEN RETURN NULL; END IF;             -- delete inactivo: sin efecto horario
    v_old_id := OLD.id_override::text;
  ELSIF TG_OP = 'UPDATE' THEN
    -- Skip SOLO si el cambio se limita a columnas NO efectivas para el resolver.
    -- "Efectiva" = toda columna que el resolver lee para APLICABILIDAD (id_cabana, fecha_desde,
    -- fecha_hasta, tipo_override, activo), VALOR (valor), o PRECEDENCIA. El desempate del resolver es
    --   ORDER BY (id_cabana IS NOT NULL) DESC, created_at DESC, id_override DESC
    -- => created_at e id_override SON efectivas (pueden cambiar el override ganador y el horario
    --    efectivo sin tocar ninguna otra columna). NO son metadata inocua.
    -- Unicas columnas inertes (pueden cambiar en un skip): motivo, creado_por, source_event.
    -- INVARIANTE: si el resolver pasa a leer otra columna, agregarla aca.
    IF NOT (
         OLD.activo       IS DISTINCT FROM NEW.activo
      OR OLD.tipo_override IS DISTINCT FROM NEW.tipo_override
      OR OLD.valor         IS DISTINCT FROM NEW.valor
      OR OLD.fecha_desde   IS DISTINCT FROM NEW.fecha_desde
      OR OLD.fecha_hasta   IS DISTINCT FROM NEW.fecha_hasta
      OR OLD.id_cabana     IS DISTINCT FROM NEW.id_cabana
      OR OLD.created_at    IS DISTINCT FROM NEW.created_at    -- desempate del resolver (created_at DESC)
      OR OLD.id_override   IS DISTINCT FROM NEW.id_override   -- ultimo desempate del resolver (id_override DESC, PK)
    ) THEN
      RETURN NULL;
    END IF;
    v_old_applies := OLD.activo;   -- lado OLD cuenta si estaba activo
    v_new_applies := NEW.activo;   -- lado NEW cuenta si queda activo
    v_old_id := OLD.id_override::text;
    v_new_id := NEW.id_override::text;
  END IF;

  -- Conjunto afectado (id_cabana, fecha):
  --   applied_set(OLD) si v_old_applies  UNION  applied_set(NEW) si v_new_applies.
  --   applied_set = (esa cabaña, o todas las activas si id_cabana IS NULL)
  --                 x [fecha_desde, COALESCE(fecha_hasta, fecha_desde)]  (semantica R0: NULL = solo fecha_desde).
  FOR rec IN
    WITH src AS (
      SELECT OLD.id_cabana AS id_cabana, OLD.fecha_desde AS fd, OLD.fecha_hasta AS fh WHERE v_old_applies
      UNION ALL
      SELECT NEW.id_cabana AS id_cabana, NEW.fecha_desde AS fd, NEW.fecha_hasta AS fh WHERE v_new_applies
    )
    SELECT DISTINCT c.id_cabana AS id_cabana, g::date AS fecha
    FROM src
    JOIN cabanas c ON (src.id_cabana IS NULL AND c.activa) OR (c.id_cabana = src.id_cabana)
    CROSS JOIN LATERAL generate_series(src.fd, COALESCE(src.fh, src.fd), interval '1 day') AS g
  LOOP
    v_verd := validar_estado_override(rec.id_cabana, rec.fecha);
    IF NOT (v_verd->>'ok')::boolean THEN
      RAISE EXCEPTION 'guard_overrides: %', (v_verd->>'error')
        USING ERRCODE = '45000',
              DETAIL = jsonb_build_object(
                'error',             v_verd->>'error',
                'id_cabana',         rec.id_cabana,
                'fecha',             rec.fecha,
                'tg_op',             TG_OP,
                'id_override_old',   v_old_id,
                'id_override_new',   v_new_id,
                'detalle_validador', v_verd
              )::text;
    END IF;
  END LOOP;

  RETURN NULL;
END;
$function$

CREATE OR REPLACE FUNCTION public.validar_estado_horario_final(p_id_cabana bigint, p_fecha date)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_res JSONB;
  v_ci  TIME;
  v_co  TIME;
BEGIN
  v_res := resolver_horario(p_id_cabana, p_fecha);

  -- El resolver rechaza valores de override invalidos (formato/cast/ventana). Propagar.
  IF NOT (v_res->>'ok')::boolean THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'override_hora_invalido',
      'id_cabana', p_id_cabana,
      'fecha', p_fecha,
      'causa', v_res->>'causa',
      'detalle_resolver', v_res
    );
  END IF;

  v_ci := (v_res->>'hora_checkin')::time;
  v_co := (v_res->>'hora_checkout')::time;

  -- Same-day: la entrada efectiva debe ser >= 2h despues de la salida efectiva.
  -- Resta de TIME (no checkout + interval) para evitar wrap de medianoche.
  IF (v_ci - v_co) < interval '2 hours' THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'override_incompatible_same_day',
      'id_cabana', p_id_cabana,
      'fecha', p_fecha,
      'hora_checkin_efectiva', v_ci,
      'hora_checkout_efectiva', v_co,
      'gap_efectivo', (v_ci - v_co),
      'gap_minimo', interval '2 hours'
    );
  END IF;

  RETURN jsonb_build_object('ok', true);
END;
$function$

CREATE OR REPLACE FUNCTION public.validar_estado_override(p_id_cabana bigint, p_fecha date)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v JSONB;
BEGIN
  v := validar_no_eventos_comprometidos(p_id_cabana, p_fecha);
  IF NOT (v->>'ok')::boolean THEN
    RETURN v;
  END IF;

  v := validar_estado_horario_final(p_id_cabana, p_fecha);
  RETURN v;
END;
$function$
